+            y: y + h * 0.3,
+        },
+        PathCmd::LineTo {
+            x: x + w - r,
+            y: y + h * 0.6,
+        },
+        PathCmd::LineTo {
+            x: x + w - r,
+            y: y + h * 0.8,
+        },
+        PathCmd::LineTo {
+            x: x + r,
+            y: y + h * 0.8,
+        },
+        PathCmd::Close,
+    ]
+}
